#include <vector>
#include <algorithm>
#include <omp.h>

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Flatten the 2‑D vector to a 1‑D array for maximal cache friendliness
    const int sz = n * n;
    int* flat = new int[sz];
    for (int i = 0; i < n; ++i)
        std::copy(path[i].begin(), path[i].end(), flat + i * n);

    // Main Floyd–Warshall using a 1‑D representation
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        int k_n = k * n;
        for (int i = 0; i < n; ++i) {
            int i_n = i * n;
            int via = flat[i_n + k];
            for (int j = 0; j < n; ++j) {
                int alt = via + flat[k_n + j];
                if (alt < flat[i_n + j])
                    flat[i_n + j] = alt;
            }
        }
    }

    // Copy back to the original 2‑D vector
    for (int i = 0; i < n; ++i)
        std::copy(flat + i * n, flat + (i + 1) * n, path[i].begin());

    delete[] flat;
}
