/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {
    // First accumulation:  x1[i] += sum_j A[i][j] * y_1[j]
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double local = 0.0;
        const auto* row = A[i].data();
        const auto* y = y_1.data();
        for (int j = 0; j < n; ++j) {
            local += row[j] * y[j];
        }
        x1[i] += local;
    }

    // Second accumulation:  x2[i] += sum_j A[j][i] * y_2[j]
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double local = 0.0;
        for (int j = 0; j < n; ++j) {
            local += A[j][i] * y_2[j];
        }
        x2[i] += local;
    }
}
