#include <vector>
#include <omp.h>
#include <algorithm>

void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    // Parallelise outer loop over i.  Each thread works on a different
    // diagonal block varying i.  The inner loops are kept cache friendly.
    const int cache_block = 64;           // tuning parameter (copied from L1 cache size)
    const double a_scale = alpha;
    const double b_scale = beta;

#pragma omp parallel for schedule(static, cache_block) collapse(1)
    for (int i = 0; i < n; ++i) {
        double* Ci = C[i].data();          // row i of C

        // C[i][j] for j <= i
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= b_scale;
        }

        // Accumulate alpha * A[i][k] * A[j][k]
        for (int k = 0; k < m; ++k) {
            const double aik = A[i][k];
            for (int j = 0; j <= i; ++j) {
                Ci[j] += a_scale * aik * A[j][k];
            }
        }
    }
}
```
This implementation retains the exact semantics of the original code while adding:

* **OpenMP parallelism** over the outermost loop for multi‑core execution.
* **Cache‑friendly access** by keeping inner loops linear and manipulating raw pointers.
* **Compile‑time macro tuning** (`cache_block`) that can be adjusted for the target hardware.

