#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B)
{
    constexpr double inv3 = 1.0 / 3.0;
    const size_t N = static_cast<size_t>(n);

    /* Pointer aliases for fast access */
    double *restrict a = A.data();
    double *restrict b = B.data();

    /* Parallelise the two body‑loops per timestep – they are independent */
    for (int t = 0; t < tsteps; ++t) {
        /* First update : B[i] = (a[i-1]+a[i]+a[i+1]) / 3 */
        #pragma omp parallel for schedule(static)
        for (size_t i = 1; i < N - 1; ++i) {
            b[i] = inv3 * (a[i-1] + a[i] + a[i+1]);
        }

        /* Second update : A[i] = (b[i-1]+b[i]+b[i+1]) / 3 */
        #pragma omp parallel for schedule(static)
        for (size_t i = 1; i < N - 1; ++i) {
            a[i] = inv3 * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
