#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    /* Form  B := alpha*A^T*B.
       A is MxM
       B is MxN
    *
    * The algorithm is cheap when the inner product
    * is performed in a cache‑friendly manner.
    * We parallelise over the outer dimension i because
    * each iteration only reads from rows k > i
    * and writes to its own row i – no write‑write
    * conflicts across threads.
    */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double sum = B[i][j];                 // current row entry
            for (int k = i + 1; k < m; ++k) {     // use only elements below diagonal
                sum += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * sum;                // final scaling
        }
    }
}
