trisolv:
```cpp
#include <vector>
#include <cstddef>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    // Use raw pointers for speed. All vectors are continuous in memory
    double* x_ptr = x.data();
    const double* b_ptr = b.data();

    for (int i = 0; i < n; ++i) {
        // Start with the RHS value
        double val = b_ptr[i];

        // Accumulate the dot product L[i][0..i-1] * x[0..i-1]
        const std::vector<double>& Li = L[i];
        const double* Li_ptr = Li.data();
        const double* x_local = x_ptr;

        // Unroll the inner loop by 4 for a small speedup
        int j = 0;
        for (; j <= i - 4; j += 4) {
            val -= Li_ptr[j  ] * x_local[j  ];
            val -= Li_ptr[j+1] * x_local[j+1];
            val -= Li_ptr[j+2] * x_local[j+2];
            val -= Li_ptr[j+3] * x_local[j+3];
        }
        for (; j < i; ++j) {
            val -= Li_ptr[j] * x_local[j];
        }

        // Divide by the diagonal element
        x_ptr[i] = val / Li_ptr[i];
    }
}
