// Optimized 2mm kernel
#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha, double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    // Get contiguous pointers to the underlying data
    double *tmp_data   = &tmp[0][0];
    double *A_data     = &A[0][0];
    double *B_data     = &B[0][0];
    double *C_data     = &C[0][0];
    double *D_data     = &D[0][0];

    // Use block size that fits comfortably in L1/L2 cache
    constexpr std::size_t BLOCK_M = 64; // rows of C (nj or nl)
    constexpr std::size_t BLOCK_K = 64; // inner dimension (nk or nj)

    // Tmp = alpha * A * B
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nk; ++k)
                sum += alpha * A_data[i * nk + k] * B_data[k * nj + j];
            tmp_data[i * nj + j] = sum;
        }
    }

    // D = beta * D + tmp * C
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nl; ++j) {
            double sum = beta * D_data[i * nl + j];
            for (int k = 0; k < nj; ++k)
                sum += tmp_data[i * nj + k] * C_data[k * nl + j];
            D_data[i * nl + j] = sum;
        }
    }
}
