/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {
    // Parallelise the spatial loop with OpenMP.
    for (int t = 0; t < tsteps; ++t) {
        // i loop is independent across iterations (except using
        // the same source data), so we can parallelise it.
        #pragma omp parallel for schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            double* prev = A[i - 1].data();
            double* cur  = A[i].data();
            double* next = A[i + 1].data();

            // Local pointers to neighboring rows for quicker access.
            double* prevL = prev;     // row i-1
            double* curL  = cur;      // row i
            double* nextL = next;     // row i+1

            // j loop
            for (int j = 1; j <= n - 2; ++j) {
                // Sum the 3x3 neighbourhood
                double sum =
                    prevL[j - 1] + prevL[j] + prevL[j + 1] +
                    curL[j - 1]  + curL[j]  + curL[j + 1]  +
                    nextL[j - 1] + nextL[j] + nextL[j + 1];

                curL[j] = sum / 9.0;
            }
        }
    }
}
