/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    // Zero the output vector y (parallel for to keep all work in the timed region)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        y[i] = 0.0;
    }

    // Retrieve raw pointers for faster access
    const double* xp = x.data();
    double* yp = y.data();
    double* tp = tmp.data();

    // Main ATAX computation. Parallelise over rows of A.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double ti = 0.0;
        const double* arow = A[i].data();

        // Compute dot product of the i-th row of A with x
        for (int j = 0; j < n; ++j) {
            ti += arow[j] * xp[j];
        }

        tp[i] = ti;

        // Accumulate contribution to y
        for (int j = 0; j < n; ++j) {
            yp[j] += arow[j] * ti;
        }
    }
}
