#include <vector>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    for (int i = 0; i < n; ++i) {
        double* const Ai = A[i].data();          // cache the pointer to the i‑th row

        /* Upper part (j < i) – compute L(i,j)  */
        for (int j = 0; j < i; ++j) {
            double sum = Ai[j];                  // start with the original value
            for (int k = 0; k < j; ++k) {
                sum -= Ai[k] * A[k][j];          // reuse A[k][j]
            }
            Ai[j] = sum / A[j][j];               // divide once
        }

        /* Lower part (j >= i) – compute U(i,j)  */
        for (int j = i; j < n; ++j) {
            double sum = Ai[j];
            for (int k = 0; k < i; ++k) {
                sum -= Ai[k] * A[k][j];
            }
            Ai[j] = sum;                         // result already U(i,j)
        }
    }
}
