```cpp
#include <cmath>
#include <vector>
#include <omp.h>

/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    for (int k = 0; k < n; ++k) {
        /* Compute norm of k-th column of A (modified Gram–Schmidt vector) */
        double nrm = 0.0;
        #pragma omp parallel for reduction(+:nrm)
        for (int i = 0; i < m; ++i) {
            const double v = A[i][k];
            nrm += v * v;
        }

        const double rkk = std::sqrt(nrm);
        R[k][k] = rkk;

        /* Normalize the k‑th column to form Q's column */
        #pragma omp parallel for
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / rkk;
        }

        /* Update remaining columns */
        for (int j = k + 1; j < n; ++j) {
            double rij = 0.0;

            /* Compute inner product Q_k · A_j */
            #pragma omp parallel for reduction(+:rij)
            for (int i = 0; i < m; ++i) {
                rij += Q[i][k] * A[i][j];
            }
            R[k][j] = rij;

            /* Orthogonalize column j: A_j -= Q_k * rij */
            #pragma omp parallel for
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * rij;
            }
        }
    }
}
