#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    // Parallel over rows of A and B
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum_tmp = 0.0;
        double sum_y   = 0.0;
        const double* const Ai = A[i].data();
        const double* const Bi = B[i].data();
        const double* const X  = x.data();

        // Unroll the inner loop for a bit of speed
        int j = 0;
        const int unroll = 4;
        const int limit = n - (n % unroll);
        for (; j < limit; j += unroll) {
            sum_tmp += Ai[j]     * X[j];
            sum_tmp += Ai[j+1] * X[j+1];
            sum_tmp += Ai[j+2] * X[j+2];
            sum_tmp += Ai[j+3] * X[j+3];

            sum_y   += Bi[j]     * X[j];
            sum_y   += Bi[j+1] * X[j+1];
            sum_y   += Bi[j+2] * X[j+2];
            sum_y   += Bi[j+3] * X[j+3];
        }
        for (; j < n; ++j) {       // remainder
            sum_tmp += Ai[j] * X[j];
            sum_y   += Bi[j] * X[j];
        }

        tmp[i] = sum_tmp;
        y[i]   = alpha * sum_tmp + beta * sum_y;
    }
}
