```cpp
#include <vector>
#include <cstddef>
#include <omp.h>

// The function signature must remain identical to the harness expectation.
void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    // --- 1. Compute column means -----------------------------------------
    // Parallel over columns. Each thread accumulates its own partial sum to
    // avoid contention on the mean array.
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / n;
    }

    // --- 2. Subtract mean from every element --------------------------------
    // Parallel over rows. Each row is independent.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
        }
    }

    // --- 3. Compute covariance matrix ---------------------------------------
    // Only the upper‑triangular part is computed directly; the lower one
    // is filled by symmetry. Parallel over i with a nested loop for j>=i.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double val = sum / (n - 1.0);
            cov[i][j] = val;
            cov[j][i] = val;   // Symmetry
        }
    }
}
