#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    /* ------------------------------------------------------------- */
    /* 1. Matrix update :  A += u1*v1^T + u2*v2^T                    */
    /* ------------------------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double ui1  = u1[i];
        const double ui2  = u2[i];
        std::vector<double>& prow = A[i];
        for (int j = 0; j < n; ++j) {
            prow[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* ------------------------------------------------------------- */
    /* 2. Update x :  x += beta * A^T * y                            */
    /* ------------------------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += A[j][i] * y[j];
        }
        x[i] += beta * sum;
    }

    /* ------------------------------------------------------------- */
    /* 3. x += z                                                     */
    /* ------------------------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* ------------------------------------------------------------- */
    /* 4. Update w :  w += alpha * A * x                             */
    /* ------------------------------------------------------------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const std::vector<double>& prow = A[i];
        for (int j = 0; j < n; ++j) {
            sum += prow[j] * x[j];
        }
        w[i] += alpha * sum;
    }
}
