#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) {
    /* Turn the 2‑D std::vector into a 1‑D contiguous array for
       faster access and better cache behaviour. */
    std::vector<double> &Araw = reinterpret_cast<std::vector<double>&>(A);
    const int N = n;
    const int N2 = N * N;

    /* =================================================================== */
    /* LU factorisation (Doolittle) with in‑place updates                    */
    /* =================================================================== */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < N; ++i) {
        /* --- Compute L part (j < i) ------------------------------------- */
        for (int j = 0; j < i; ++j) {
            double w = A[i*N + j];
            for (int k = 0; k < j; ++k) {
                w -= A[i*N + k] * A[k*N + j];
            }
            A[i*N + j] = w / A[j*N + j];
        }

        /* --- Compute U part (j >= i) ------------------------------------- */
        for (int j = i; j < N; ++j) {
            double w = A[i*N + j];
            for (int k = 0; k < i; ++k) {
                w -= A[i*N + k] * A[k*N + j];
            }
            A[i*N + j] = w;
        }
    }

    /* =================================================================== */
    /* Forward substitution: solve Ly = b                                  */
    /* =================================================================== */
    for (int i = 0; i < N; ++i) {
        double w = b[i];
        for (int j = 0; j < i; ++j) {
            w -= A[i*N + j] * y[j];
        }
        y[i] = w;
    }

    /* =================================================================== */
    /* Backward substitution: solve Ux = y                                 */
    /* =================================================================== */
    for (int i = N-1; i >= 0; --i) {
        double w = y[i];
        for (int j = i+1; j < N; ++j) {
            w -= A[i*N + j] * x[j];
        }
        x[i] = w / A[i*N + i];
    }
}
