#include <vector>
#include <cstring>
#include <omp.h>

void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r) {
    // Initialise s and q to zero (parallelised for speed)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) s[i] = 0.0;

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) q[i] = 0.0;

    // Main kernel
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double row_q = 0.0;                // local partial sum for q[i]
        const std::vector<double>& Ai = A[i];
        const double ri = r[i];

        for (int j = 0; j < m; ++j) {
            // Atomic update of s[j]
            #pragma omp atomic
            s[j] += ri * Ai[j];

            // Accumulate q[i] locally then write at end (no race)
            row_q += Ai[j] + p[j];
        }
        q[i] = row_q;
    }
}
