#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G) {

    /* ------------------------------------------------------------------
       1. Compute E = A * B   (ni × nj)
       ------------------------------------------------------------------ */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        const double* const Ai = A[i].data();
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nk; ++k) {
                sum += Ai[k] * B[k][j];
            }
            E[i][j] = sum;
        }
    }

    /* ------------------------------------------------------------------
       2. Compute F = C * D   (nj × nl)
       ------------------------------------------------------------------ */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < nj; ++i) {
        const double* const Ci = C[i].data();
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nm; ++k) {
                sum += Ci[k] * D[k][j];
            }
            F[i][j] = sum;
        }
    }

    /* ------------------------------------------------------------------
       3. Compute G = E * F   (ni × nl)
       ------------------------------------------------------------------ */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        const double* const Ei = E[i].data();
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nj; ++k) {
                sum += Ei[k] * F[k][j];
            }
            G[i][j] = sum;
        }
    }
