#include <vector>
#include <cstddef>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {

    // ensure y has size n (the harness guarantees this)
    double* yptr = y.data();
    const double* rptr = r.data();

    yptr[0] = -rptr[0];
    double beta  = 1.0;
    double alpha = -rptr[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // compute dot product of r[k-i-1] and y[i] for i=0..k-1
        double sum = 0.0;
        for (int i = 0; i < k; ++i) {
            sum += rptr[k - i - 1] * yptr[i];
        }

        alpha = -(rptr[k] + sum) / beta;

        // update y[0..k-1] in-place   (no temporary needed)
        for (int i = 0; i < k; ++i) {
            yptr[i] += alpha * yptr[k - i - 1];
        }

        yptr[k] = alpha;
    }
}
