    double* sum_local = static_cast<double*>(std::malloc(np * sizeof(double)));

    /* Each thread processes a subset of (r,q) pairs.  The collapse
       clause allows a simple 1‑D iteration space equal to nr*nq
       which keeps the work well balanced. */
