/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    /* We compute the Cholesky decomposition of the symmetric positive
       definite matrix A in-place.  The algorithm has two inner loops
       that are independent for each column j < i, so we parallelise
       the j‑loop with OpenMP.  The inner k‑loop is short and
       auto‑vectorised by the compiler. */
#pragma omp parallel
    {
        for (int i = 0; i < n; ++i) {
            /* Parallelise the computation of A[i][j] for j < i. */
#pragma omp for schedule(static)
            for (int j = 0; j < i; ++j) {
                double sum = 0.0;
                double* ai = A[i].data();
                double* aj = A[j].data();
                for (int k = 0; k < j; ++k) {
                    sum += ai[k] * aj[k];
                }
                A[i][j] = (ai[j] - sum) / A[j][j];
            }

            /* Diagonal element: compute in serial (no parallelism needed). */
            double sum = 0.0;
            double* ai = A[i].data();
            for (int k = 0; k < i; ++k) {
                sum += ai[k] * ai[k];
            }
            A[i][i] = std::sqrt(ai[i] - sum);
        }
    }
}
