/*  Optimised kernel_syr2k – keeps original signature but
    re‑interprets the 2‑D std::vector containers as
    contiguous C arrays.  The code uses OpenMP for
    parallelisation, stores the index math in registers
    and eliminates redundant computations.  The loop
    ordering is chosen to maximise cache reuse and avoid
    write conflicts between threads. */

#include <vector>
#include <cstddef>
#include <cstdint>
#include <omp.h>

inline double *row(double **a, std::size_t i) {
    return a[i];
}

void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B) {
    // Flatten the underlying storage for speed.
    // `C` is n×n, `A` and `B` are n×m.
    double *Cflat = new double[n * n];
    double *Aflat = new double[n * m];
    double *Bflat = new double[n * m];

    // Copy data into linear arrays
    for (int i = 0; i < n; ++i) {
        double *crow = Cflat + i * n;
        double *arow = Aflat + i * m;
        double *brow = Bflat + i * m;
        std::copy(C[i].begin(), C[i].end(), crow);
        std::copy(A[i].begin(), A[i].end(), arow);
        std::copy(B[i].begin(), B[i].end(), brow);
    }

    /*  Parallel over the outer dimension.  Each thread works
        on a contiguous block of rows, so writes to C are
        isolated and no critical sections are required.  */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *Ci = Cflat + i * n;
        double *Bi = Bflat + i * m;
        /* Beta scaling – only lower triangle is touched. */
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        /* Main accumulation loop.  The two symmetry‑related
           products are merged to reduce memory traffic.  */
        for (int k = 0; k < m; ++k) {
            double alphaBik = Bflat[i * m + k] * alpha;
            double alphaAik = Aflat[i * m + k] * alpha;
            double *Ak   = Aflat + k; // column k
            double *Bk   = Bflat + k; // column k
            /* Instead of addressing C[j][i] we directly
               accummulate into the lower triangular part.  */
            for (int j = 0; j <= i; ++j) {
                Ci[j] += alphaBik * Aflat[j * m + k] + alphaAik * Bflat[j * m + k];
            }
        }
    }

    /* Copy result back into the original std::vector container. */
    for (int i = 0; i < n; ++i) {
        std::copy(Cflat + i * n, Cflat + (i + 1) * n, C[i].begin());
    }

    delete[] Cflat;
    delete[] Aflat;
    delete[] Bflat;
}
```
This implementation keeps the input and output signatures unchanged but internally rearranges the data to contiguous arrays, applies OpenMP for parallelisation, and reorganises the loops to maximize cache locality and reduce the number of arithmetic operations.

