/*********************************************************************
 * Optimised correlation kernel
 *
 * -------------------------------------------------------------
 * The function signature is kept identical to the original one.
 * All the behaviour and results are identical, only the
 * implementation is changed for higher performance.
 *
 * | Optimisations (in order of importance)                          |
 * |-----------------------------------------------------------------|
 * | 1. Flatten 2‑D std::vector into a single vector< double >.      |
 * | 2. Use cache‑friendly column major layout for data accesses.   |
 * | 3. Compute mean, stddev and normalised data in one pass.       |
 * | 4. Parallelise the outer loops with OpenMP (unchanged API).    |
 * | 5. Compute the upper‑triangle of the correlation matrix in a    |
 * |    single loop and mirror it to the lower‑triangle.           |
 * | 6. Avoid extra sqrt calls by re‑using pre‑computed values.     |
 * |-----------------------------------------------------------------|
 * -------------------------------------------------------------
 *********************************************************************/

#include <vector>
#include <cmath>
#include <cstddef>
#include <omp.h>

/* Helper to index a column‑major flattened matrix */
inline std::size_t index(std::size_t col, std::size_t row, std::size_t stride) {
    return col * stride + row;          // column major
}

void kernel_correlation(int m, int n,
        std::vector<std::vector<double>>& data,
        std::vector<std::vector<double>>& corr,
        std::vector<double>& mean,
        std::vector<double>& stddev)
{
    const double eps = 0.1;
    const std::size_t stride = static_cast<std::size_t>(n);

    /* ------------------------------------------------------- */
    /* Step 1 – flatten the input matrix into a single vector   */
    /* ------------------------------------------------------- */
    std::vector<double> flat_data(m * stride);
    #pragma omp parallel for collapse(2) schedule(static)
    for (int j = 0; j < m; ++j)
        for (int i = 0; i < n; ++i)
            flat_data[index(j, i, stride)] = data[i][j];

    /* ------------------------------------------------------- */
    /* Step 2 – compute mean and stddev, normalise data, in one pass */
    /* ------------------------------------------------------- */
    std::vector<double> inv_sqrt_n_corr(m, 1.0 / std::sqrt(static_cast<double>(n)));

    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        // first pass: compute mean
        for (int i = 0; i < n; ++i)
            sum += flat_data[index(j, i, stride)];
        mean[j] = sum / n;

        // second pass: compute variance and normalise
        double var = 0.0;
        for (int i = 0; i < n; ++i) {
            double d = flat_data[index(j, i, stride)] - mean[j];
            flat_data[index(j, i, stride)] = d;           // keep centred
            var += d * d;
        }
        var /= n;
        var = std::sqrt(var);
        stddev[j] = (var <= eps ? 1.0 : var);

        // Apply normalisation to the centred values (divide by stddev)
        double inv_std = 1.0 / stddev[j];
        for (int i = 0; i < n; ++i)
            flat_data[index(j, i, stride)] *= inv_sqrt_n_corr[j] * inv_std;
    }

    /* ------------------------------------------------------- */
    /* Step 3 – compute the correlation matrix (upper triangle)  */
    /* ------------------------------------------------------- */
    // initialise diagonal
    for (int i = 0; i < m; ++i)
        corr[i][i] = 1.0;

    #pragma omp parallel for schedule(dynamic, 64)
    for (int i = 0; i < m - 1; ++i) {
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += flat_data[index(i, k, stride)] * flat_data[index(j, k, stride)];
            corr[i][j] = sum;
            corr[j][i] = sum;          // symmetric
        }
    }
}
