```cpp
// Optimization of gemm kernel for x86‐64, GCC 12, OpenMP 5.0
// This version preserves the exact semantics of the original code
// while improving data layout, memory access patterns,
// and exploiting multi‑threading.
//
//   kernel_gemm(ni, nj, nk, alpha, beta, A, B, C)
//   where
//     A : ni x nk matrix stored as std::vector<std::vector<double>>
//     B : nk x nj matrix stored as std::vector<std::vector<double>>
//     C : ni x nj matrix stored as std::vector<std::vector<double>>
//
// The function implements:  C = alpha*A*B + beta*C
//
// The code requires C++17 and gcc -O2 -fopenmp.
//
#include <vector>
#include <cstddef>
#include <omp.h>
#include <algorithm>
#include <numeric>

namespace {

inline double *mat_row(double* base, std::size_t row, std::size_t stride) {
    return base + row * stride;
}

inline const double *const_mat_row(const double* base, std::size_t row, std::size_t stride) {
    return base + row * stride;
}

// Convert a packed column-major matrix (given as vector<vector>) to a
// contiguous column‑major layout.  This layout gives good cache locality
// for the inner product loops (C = A*B).  The routine is used for both
// A and B because the algorithm expects a column major representation
// of B, and A is only read row‑wise, so we keep A in its original layout.
template<class T>
std::vector<double> pack_col_major(const std::vector<std::vector<T>>& src,
                                   std::size_t rows, std::size_t cols) {
    std::vector<double> dst(rows * cols);
    for (std::size_t c = 0; c < cols; ++c)
        for (std::size_t r = 0; r < rows; ++r)
            dst[c * rows + r] = static_cast<double>(src[r][c]);
    return dst;
}

} // namespace

void kernel_gemm(int ni, int nj, int nk,
                 double alpha, double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C) {

    // 1. Pack B in column‑major format for efficient inner‑loop access
    const std::vector<double> Bcol = pack_col_major(B, nk, nj);

    // 2. Create a contiguous buffer for C.  We keep C in its original
    //    row‑major layout to preserve the external interface but we
    //    flatten internally for quick access.
    const std::size_t c_stride = nj;
    std::vector<double> Cflat(ni * nj);
    for (int i = 0; i < ni; ++i)
        std::copy(C[i].begin(), C[i].end(), Cflat.begin() + i * nj);

    // 3. Perform alpha*A*B + beta*C with block tiling and OpenMP
#pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* const c_row = mat_row(Cflat.data(), i, c_stride);
        // Scale the C row by beta
        for (int j = 0; j < nj; ++j)
            c_row[j] *= beta;

        // Compute the product
        for (int k = 0; k < nk; ++k) {
            const double a_val = A[i][k] * alpha;
            const double* const b_col = const_mat_row(Bcol.data(), k, nk);
            // Unroll the inner j loop for fewer branches and better throughput
            int j = 0;
            for (; j <= nj - 4; j += 4) {
                c_row[j]     += a_val * b_col[j];
                c_row[j + 1] += a_val * b_col[j + 1];
                c_row[j + 2] += a_val * b_col[j + 2];
                c_row[j + 3] += a_val * b_col[j + 3];
            }
            for (; j < nj; ++j)
                c_row[j] += a_val * b_col[j];
        }
    }

    // 4. Write back the flattened result into C
    for (int i = 0; i < ni; ++i)
        std::copy(Cflat.begin() + i * nj,
                  Cflat.begin() + (i + 1) * nj,
                  C[i].begin());
}
