    const double c2 = 0.7;

    for (int t = 0; t < tmax; ++t) {
        /* 1. Update boundary Ey[0][j] */
        #pragma omp parallel for schedule(static)
        for (int j = 0; j < ny; ++j) {
            ey[0][j] = _fict_[t];
        }

        /* 2. Update Ey for i >= 1 */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < nx; ++i) {
            double* ey_i     = ey[i].data();
            double* ey_im1   = ey[i - 1].data();
            double* hz_i     = hz[i].data();
            double* hz_im1   = hz[i - 1].data();
            for (int j = 0; j < ny; ++j) {
                ey_i[j] -= c1 * (hz_i[j] - hz_im1[j]);
            }
        }

        /* 3. Update Ex for j >= 1 */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx; ++i) {
            double* ex_i     = ex[i].data();
            double* hz_i     = hz[i].data();
            double* hz_im1   = hz[i].data();  // same row, j-1 index inside loop
            for (int j = 1; j < ny; ++j) {
                ex_i[j] -= c1 * (hz_i[j] - hz_i[j - 1]);
            }
        }

        /* 4. Update Hz */
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx - 1; ++i) {
            double* hz_i      = hz[i].data();
            double* hz_ip1    = hz[i + 1].data();
            double* ex_i      = ex[i].data();
            double* ey_i      = ey[i].data();
            double* ey_ip1    = ey[i + 1].data();
            for (int j = 0; j < ny - 1; ++j) {
                hz_i[j] -= c2 * (ex_i[j + 1] - ex_i[j] + ey_ip1[j] - ey_i[j]);
            }
        }
