                    const int idx_m = (i - 1) * strideX + j * strideY + k * strideZ;
                    const int idx_p = (i + 1) * strideX + j * strideY + k * strideZ;
                    const int idx_jm= i * strideX + (j - 1) * strideY + k * strideZ;
                    const int idx_jp= i * strideX + (j + 1) * strideY + k * strideZ;
                    const int idx_km= i * strideX + j * strideY + (k - 1) * strideZ;
                    const int idx_kp= i * strideX + j * strideY + (k + 1) * strideZ;

                    const double center = a[idx];
                    b[idx] = coeff * (a[idx_p] - 2.0 * center + a[idx_m]) +
                             coeff * (a[idx_jp] - 2.0 * center + a[idx_jm]) +
                             coeff * (a[idx_kp] - 2.0 * center + a[idx_km]) +
                             center;
                }
            }
        }

#pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
