/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Optimised by a C++ performance engineer */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    // Pre‑compute constants once
    const float alpha_f = static_cast<float>(alpha);
    const float e_a   = std::exp(-alpha_f);          // exp(-α)
    const float e_2a  = std::exp(-2.0f * alpha_f);  // exp(-2α)
    const float k     = 1.0f - e_a*(1.0f - e_a)/(1.0f + 2.0f*alpha_f*e_a - e_2a);
    const float a1    = k;
    const float a2    = k * e_a * (alpha_f - 1.0f);
    const float a3    = k * e_a * (alpha_f + 1.0f);
    const float a4    = -k * e_2a;
    const float a5    = k;
    const float a6    = a2;
    const float a7    = a3;
    const float a8    = a4;
    const float b1    = std::pow(2.0f, -alpha_f);
    const float b2    = -e_2a;
    const float c1    = 1.0f;
    const float c2    = 1.0f;

    // Forward pass over rows
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float x = imgIn[i][j];
            float y = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1[i][j]  = y;
            xm1 = x;
            ym2 = ym1;
            ym1 = y;
        }

        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h-1; j >= 0; --j) {
            const float x = imgIn[i][j];
            float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2[i][j]  = y;
            xp2 = xp1;
            xp1 = x;
            yp2 = yp1;
            yp1 = y;
        }
    }

    // Accumulate row results into imgOut
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);
        }
    }

    // Forward pass over columns
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float x = imgOut[i][j];
            float y = a5 * x + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j]  = y;
            tm1 = x;
            ym2 = ym1;
            ym1 = y;
        }
    }

    // Backward pass over columns
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            const float x = imgOut[i][j];
            float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j]  = y;
            tp2 = tp1;
            tp1 = x;
            yp2 = yp1;
            yp1 = y;
        }
    }

    // Final accumulation
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
