#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {

    // => Form C := alpha*A*B + beta*C
    // A is MxM, B is MxN, C is MxN
    // The algorithm below follows the standard (upper‑triangular)
    // BLAS‑style order.

    // Pre‑fetch row pointers for C to reduce indexing overhead
    std::vector<double*> C_rows(m);
    for (int i = 0; i < m; ++i) C_rows[i] = C[i].data();

    for (int i = 0; i < m; ++i) {
        const double* A_i = A[i].data();   // row of A
        const double* B_i = B[i].data();   // row of B
        double Ai_i = A_i[i];              // A[i][i], used in every j
        double* C_i = C_rows[i];           // row of C

        // OpenMP over the inner j–loop; each thread works on a distinct j
        #pragma omp parallel for schedule(static)
        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            double Bij = B_i[j];

            // Update the previous rows (k < i)
            for (int k = 0; k < i; ++k) {
                double Bik = B[k][j];
                double aik = A_i[k];
                // C[k][j] += alpha * B[i][j] * A[i][k]
                C_rows[k][j] += alpha * Bij * aik;
                // Accumulate for the current row
                temp2 += Bik * aik;
            }

            // Update current row
            C_i[j] = beta * C_i[j] + alpha * Bij * Ai_i + alpha * temp2;
        }
    }
}
