#include <vector>
#include <cstring>
#include <omp.h>

// Helper to access a flattened 2D array in row-major order
inline double* row(double* data, int n, int i) { return data + i * n; }

void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    // Convert the 2‑D std::vector to a single contiguous block for each matrix
    std::vector<double> u_buf(n * n);
    std::vector<double> v_buf(n * n);
    std::vector<double> p_buf(n * n);
    std::vector<double> q_buf(n * n);

    // Flatten the original data
    for (int i = 0; i < n; ++i)
        std::memcpy(&u_buf[i * n], u[i].data(), n * sizeof(double));
    for (int i = 0; i < n; ++i)
        std::memcpy(&v_buf[i * n], v[i].data(), n * sizeof(double));
    for (int i = 0; i < n; ++i)
        std::memcpy(&p_buf[i * n], p[i].data(), n * sizeof(double));
    for (int i = 0; i < n; ++i)
        std::memcpy(&q_buf[i * n], q[i].data(), n * sizeof(double));

    const double dx = 1.0 / n;
    const double dy = 1.0 / n;
    const double dt = 1.0 / tsteps;
    const double mul1 = 2.0 * dt / (dx * dx);
    const double mul2 = 1.0 * dt / (dy * dy);

    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    // Loop over time steps
    for (int t = 1; t <= tsteps; ++t)
    {
        // First sweep (vertical direction)
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            double* v_row = row(v_buf, n, i);
            double* p_row = row(p_buf, n, i);
            double* q_row = row(q_buf, n, i);
            double* u_row_m1 = row(u_buf, n, i - 1);
            double* u_row = row(u_buf, n, i);
            double* u_row_p1 = row(u_buf, n, i + 1);

            // Boundary initialization
            v_row[0]          = 1.0;
            p_row[0]          = 0.0;
            q_row[0]          = v_row[0];

            // Forward sweep (j = 1 .. n-2)
            for (int j = 1; j < n - 1; ++j)
            {
                double denom = a * p_row[j-1] + b;
                p_row[j] = -c / denom;
                q_row[j] = (-d * u_row_m1[j] + (1.0 + 2.0 * d) * u_row[j]
                            - f * u_row_p1[j] - a * q_row[j-1]) / denom;
            }

            v_row[n-1] = 1.0;

            // Backward sweep (j = n-2 .. 1)
            for (int j = n - 2; j >= 1; --j)
                v_row[j] = p_row[j] * v_row[j+1] + q_row[j];
        }

        // Second sweep (horizontal direction)
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            double* u_row = row(u_buf, n, i);
            double* p_row = row(p_buf, n, i);
            double* q_row = row(q_buf, n, i);
            double* v_row_m1 = row(v_buf, n, i - 1);
            double* v_row = row(v_buf, n, i);
            double* v_row_p1 = row(v_buf, n, i + 1);

            // Boundary initialization
            u_row[0]          = 1.0;
            p_row[0]          = 0.0;
            q_row[0]          = u_row[0];

            // Forward sweep (j = 1 .. n-2)
            for (int j = 1; j < n - 1; ++j)
            {
                double denom = d * p_row[j-1] + e;
                p_row[j] = -f / denom;
                q_row[j] = (-a * v_row_m1[j] + (1.0 + 2.0 * a) * v_row[j]
                            - c * v_row_p1[j] - d * q_row[j-1]) / denom;
            }

            u_row[n-1] = 1.0;

            // Backward sweep (j = n-2 .. 1)
            for (int j = n - 2; j >= 1; --j)
                u_row[j] = p_row[j] * u_row[j+1] + q_row[j];
        }
    }

    // Copy back into the original vectors
    for (int i = 0; i < n; ++i)
        std::memcpy(u[i].data(), &u_buf[i * n], n * sizeof(double));
    for (int i = 0; i < n; ++i)
        std::memcpy(v[i].data(), &v_buf[i * n], n * sizeof(double));
    for (int i = 0; i < n; ++i)
        std::memcpy(p[i].data(), &p_buf[i * n], n * sizeof(double));
    for (int i = 0; i < n; ++i)
        std::memcpy(q[i].data(), &q_buf[i * n], n * sizeof(double));
}
